sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	function TestCase_AppDelete(vApp,vExpected)
	{
		function TestCase_AppDelete_CheckResult(vInput,vExpected,vResult)
		{
			return (vExpected == vResult);
		}
		
		test.TestCase(
			'Function AppDelete()',
			AppDelete,
			{
				'vApp': vApp
			},
			vExpected,
			TestCase_AppDelete_CheckResult);
	}
		
	TestCase_AppDelete(null,false);

	var strApp1SysId = AppCreate('Test App 1 (ATF)','scoped','x_snc_testatf1');
	TestCase_AppDelete(strApp1SysId,true);

	var strApp2SysId = AppCreate('Test App 2 (ATF)','scoped','x_snc_testatf2');
	var grApp2 = GetAppRecord(strApp2SysId);
	TestCase_AppDelete(grApp2.sys_id,true);

	var strApp3SysId = AppCreate('Test App 3 (ATF)','scoped','x_snc_testatf3');
	var grApp3 = GetAppRecord(strApp3SysId);
	AppBuilder('x_snc_testatf3'); 	
	TestCase_AppDelete(grApp3.scope,true);

	var grMeta = new GlideRecord('sys_metadata');
	grMeta.addQuery('sys_scope','=',strApp3SysId);
	grMeta.addQuery('sys_class_name','!=','sys_metadata_delete');
	grMeta.query();
	if (grMeta.getRowCount() > 0)
	{
		test.Log('FAILED: There are app files left from App 3 ('+strApp3SysId+'):');
		test.SetResult(false);
	}
	while (grMeta.next() == true)
	{
		test.Log(RenderRecordSummary(grMeta));
	}

	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
